query DiscoveryViewFCSequencingReadsQuery(
  $input: queryInput_fedSequencingReads_input_Input
) {
  fedSequencingReads(input: $input) {
    id
    nucleicAcid
    protocol
    medakaModel
    technology
    taxon {
      name
    }
    sample {
      railsSampleId
      name
      notes
      collectionLocation
      sampleType
      waterControl
      uploadError
      hostOrganism {
        name
      }
      collection {
        name
        public
      }
      ownerUserId
      ownerUserName
      metadatas {
        edges {
          node {
            fieldName
            value
          }
        }
      }
    }
    consensusGenomes {
      edges {
        node {
          producingRunId
          taxon {
            name
          }
          accession {
            accessionId
            accessionName
          }
          metrics {
            coverageDepth
            totalReads
            gcPercent
            refSnps
            percentIdentity
            nActg
            percentGenomeCalled
            nMissing
            nAmbiguous
            referenceGenomeLength
          }
        }
      }
    }
  }
}

query DiscoveryViewFCWorkflowsQuery(
  $input: queryInput_fedWorkflowRuns_input_Input
) {
  fedWorkflowRuns(input: $input) {
    id
    startedAt
    status
    errorLabel
    rawInputsJson
    workflowVersion {
      version
      workflow {
        name
      }
    }
    entityInputs {
      edges {
        node {
          inputEntityId
          entityType
        }
      }
    }
  }
}

query DiscoveryViewFCFedWorkflowRunsAggregateQuery(
  $input: queryInput_fedWorkflowRunsAggregate_input_Input
) {
  fedWorkflowRunsAggregate(input: $input) {
    aggregate {
      groupBy {
        collectionId
        workflowVersion {
          workflow {
            name
          }
        }
      }
      count
    }
  }
}

query DiscoveryViewFCFedWorkflowsTotalCountQuery(
  $input: queryInput_fedWorkflowRunsAggregateTotalCount_input_Input
) {
  fedWorkflowRunsAggregateTotalCount(input: $input) {
    aggregate {
      count
      groupBy {
        workflowVersion {
          workflow {
            name
          }
        }
      }
    }
  }
}

query ConsensusGenomeReportQuery(
  $workflowRunId: String
) {
  fedConsensusGenomes(input: {where: {producingRunId: {_eq: $workflowRunId}}}) {
    ...ConsensusGenomeMetricsTableFragment
    ...ConsensusGenomeCoverageViewFragment
    ...ConsensusGenomeHistogramFragment
  }
}

fragment ConsensusGenomeCoverageViewFragment on query_fedConsensusGenomes_items {
  accession {
    accessionId
  }
  taxon {
    name
    id
  }
  metrics {
    coverageBreadth
    coverageDepth
    coverageTotalLength
  }
  referenceGenome {
    file {
      downloadLink {
        url
      }
    }
  }
}

fragment ConsensusGenomeHistogramFragment on query_fedConsensusGenomes_items {
  accession {
    accessionId
    accessionName
  }
  taxon {
    name
  }
  metrics {
    coverageViz
    coverageBinSize
    coverageTotalLength
  }
}

fragment ConsensusGenomeMetricsTableFragment on query_fedConsensusGenomes_items {
  taxon {
    name
  }
  metrics {
    mappedReads
    nActg
    nAmbiguous
    nMissing
    refSnps
    percentIdentity
    gcPercent
    percentGenomeCalled
  }
}
